### 3. Obsah pre `index.tsx`

Toto je hlavný spúšťací súbor vašej React aplikácie. Dôležitá zmena je pridanie riadku `import './index.css';`, ktorý načíta všetky štýly.

```tsx
import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import { LanguageProvider } from './components/LanguageContext';
import './index.css'; // This line is crucial for loading Tailwind styles

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('/sw.js')
      .then(registration => {
        console.log('PWA Service Worker registered: ', registration);
      })
      .catch(registrationError => {
        console.log('PWA SW registration failed: ', registrationError);
      });
  });
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <LanguageProvider>
      <App />
    </LanguageProvider>
  </React.StrictMode>
);

