import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons, adhocTasks as initialAdhocTasks } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [adhocTasks, setAdhocTasks] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  const isFirstLoad = useRef(true);

  const normalSound = useRef<HTMLAudioElement | null>(null);
  const urgentSound = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Preload sounds
    normalSound.current = new Audio('data:audio/mp3;base64,');
    urgentSound.current = new Audio('data:audio/mp3;base64,');
  }, []);

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN') return true;
      const currentRole = roles.find(r => r.name === currentUserRole);
      if (!currentRole) return false;
      return permissions.some(p => p.roleId === currentRole.id && p.permissionName === permName);
  };

  useEffect(() => {
    const q = query(collection(db, 'tasks')); 
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 15000)) { // Widen window
                      if (hasPermission('perm_play_sound')) {
                          try {
                              const soundToPlay = (task.priority === 'URGENT' || task.priority === 'AD-HOC') ? urgentSound.current : normalSound.current;
                              soundToPlay?.play().catch(e => console.warn('Sound playback blocked by browser', e));
                          } catch (e) { console.error("Error playing sound:", e); }
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      const priorityOrder: Record<string, number> = { 'AD-HOC': 0, 'URGENT': 1, 'NORMAL': 2, 'LOW': 3 };

      const sortedTasks = [...newTasks].sort((a, b) => {
        // Unfinished tasks first
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;

        // If both are done, sort by completion time descending (newest first)
        if (a.isDone && b.isDone) {
            const timeA = a.completedAt || 0;
            const timeB = b.completedAt || 0;
            return timeB - timeA;
        }

        // If both are unfinished, sort by priority
        if (!a.isDone && !b.isDone) {
            const pA = priorityOrder[a.priority || 'NORMAL'];
            const pB = priorityOrder[b.priority || 'NORMAL'];
            if (pA !== pB) return pA - pB;
        }

        // As a fallback, sort by creation time ascending (oldest first)
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    }, (error) => {
        console.error("Firestore tasks listener error:", error);
    });
    return () => unsubscribe();
  }, [roles, permissions, currentUserRole]); // Re-subscribe if permissions change

