    onClearNotification: (id: string) => void;
    installPrompt: any;
    onInstallApp: () => void;
    onDeleteMissingItem: (id: string) => void;
  }

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, hasPermission, onLogout, 
    tasks, onAddTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, 
    parts, workplaces, adhocTasks, breakSchedules, isBreakActive, bomItems
  } = props;

  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'permissions'>('entry');
  const [selectedPart, setSelectedPart] = useState<DBItem | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');

  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [activeNotification, setActiveNotification] = useState<Notification | null>(null);

  // BOM State
  const [bomParentPart, setBomParentPart] = useState<string | null>(null);
  const [bomQuantity, setBomQuantity] = useState('1');
  const [bomResults, setBomResults] = useState<{ childPart: string; quantity: number }[]>([]);
  const [bomWorkplace, setBomWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());

  const { t, language, setLanguage } = useLanguage();
  const unfinishedTasksCount = (tasks || []).filter(t => !t.isDone).length;

  // FIX: Added guards `|| []` to prevent crash on initial render
  const workplaceStrings = (workplaces || []).map(w => w.value);
  const adhocTaskStrings = (adhocTasks || []).map(a => a.value);

  useEffect(() => {
    if (notifications && notifications.length > 0) {
      if(hasPermission('perm_push_notification')) {
        const latest = notifications[0];
        setActiveNotification(latest);
      }
    }
  }, [notifications, hasPermission]);

  const handleClearAndCloseNotification = () => {
    if (activeNotification) {
      onClearNotification(activeNotification.id);
      setActiveNotification(null);
    }
  };

  const handleSendToTasks = () => {
    const partToSend = priority === 'AD-HOC' ? selectedPart?.value ?? null : selectedPart?.value ?? null;
    onAddTask(partToSend, selectedWorkplace, quantity, quantityUnit, priority);
    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
    // Reset form
    setSelectedPart(null);
    setSelectedWorkplace(null);
    setQuantity('');
    setPriority('NORMAL');
  };

  const handleCalculateBOM = () => {
    if (!bomParentPart || !bomQuantity) return;
    const qty = parseInt(bomQuantity, 10);
    const children = (bomItems || []).filter(item => item.parentPart === bomParentPart);
    const results = children.map(child => ({
        childPart: child.childPart,
        quantity: child.quantity * qty
    }));
    setBomResults(results);
    setClickedBOMTasks(new Set()); // Reset clicked status on new calculation
  };

  const handleCreateTaskFromBOM = (childPart: string, requiredQty: number) => {
    setActiveTab('entry');
    setPriority('NORMAL');
    const partObject = parts.find(p => p.value === childPart);
    setSelectedPart(partObject || { id: `adhoc-${childPart}`, value: childPart });
    setQuantity(String(Math.ceil(requiredQty)));
    setQuantityUnit('pcs');
    if(bomWorkplace) setSelectedWorkplace(bomWorkplace);

    setClickedBOMTasks(prev => new Set(prev).add(childPart));
  };

  const requestNotificationPermission = () => {
    if ('Notification' in window) {
      Notification.requestPermission().then(permission => {
        if (permission === 'granted') {
          new Notification('Notifikácie sú povolené!');
        }
      });
    }
  };

  return (
    <div className="w-full h-full p-2 md:p-8">
      {/* ... (rest of the component JSX, which is now safe from .map errors) */}
    </div>
  );
};

export default PartSearchScreen;
