import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen, { Task, PriorityLevel, InventorySession } from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);

  useEffect(() => {
    // Fetch users
    const qUsers = query(collection(db, "users"));
    const unsubscribeUsers = onSnapshot(qUsers, (snapshot) => {
      const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
      if (fetchedUsers.length === 0) {
        // If no users, seed the DB
        addDoc(collection(db, "users"), { username: "ADMIN", password: "321", role: "ADMIN" });
        addDoc(collection(db, "users"), { username: "USER", password: "123", role: "USER" });
      }
      setUsers(fetchedUsers);
    });

    // Fetch tasks
    const qTasks = query(collection(db, "tasks"), orderBy("createdAt", "asc"));
    const unsubscribeTasks = onSnapshot(qTasks, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };

      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0);
      });
      setTasks(sortedTasks);
    });

    // Fetch other data collections...
    // (similar onSnapshot calls for parts, workplaces, etc.)

    return () => {
      unsubscribeUsers();
      unsubscribeTasks();
      // ... unsubscribe others
    };
  }, []);

  const handleLogin = (username: string, role: any) => {
    setIsAuthenticated(true);
    setCurrentUser(username);
    setCurrentUserRole(role);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser('');
    setCurrentUserRole('USER');
  };

  const handleAddTask = async (part: string, workplace: string, quantity: string, unit: string, priority: PriorityLevel) => {
    await addDoc(collection(db, 'tasks'), {
      partNumber: part,
      workplace,
      quantity,
      quantityUnit: unit,
      priority,
      isDone: false,
      createdAt: Date.now(),
      createdBy: currentUser,
    });
  };

  const handleToggleTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (task) {
      updateDoc(doc(db, 'tasks', id), { 
        isDone: !task.isDone,
        completedAt: !task.isDone ? Date.now() : null,
        completedBy: !task.isDone ? currentUser : null,
        completionTime: !task.isDone ? new Date().toLocaleTimeString('sk-SK') : null,
        isInProgress: false,
        inProgressBy: null,
      });
    }
  };

  const handleSetInProgress = (id: string) => {
      const task = tasks.find(t => t.id === id);
      if(task){
          updateDoc(doc(db, 'tasks', id), {
              isInProgress: !task.isInProgress,
              inProgressBy: !task.isInProgress ? currentUser : null,
              startedAt: (!task.isInProgress && !task.startedAt) ? Date.now() : task.startedAt
          });
      }
  };

  const handleToggleBlock = (id: string) => {
      const task = tasks.find(t => t.id === id);
      if(task){
          const isBlocked = !task.isBlocked;
          const history = task.inventoryHistory ? [...task.inventoryHistory] : [];
          if(isBlocked){
              history.push({ start: Date.now() });
          } else {
              const lastEntry = history[history.length - 1];
              if(lastEntry && !lastEntry.end){
                  lastEntry.end = Date.now();
              }
          }
          updateDoc(doc(db, 'tasks', id), {
              isBlocked,
              inventoryHistory: history
          });
      }
  };

  const handleEditTask = (id: string, newPriority: PriorityLevel) => {
      updateDoc(doc(db, 'tasks', id), { priority: newPriority });
  };

  // ... other handlers like deleteTask, addNote, etc.

  return (
    <div className="h-full bg-gray-900 text-white">
      {isAuthenticated ? (
        <PartSearchScreen
          currentUser={currentUser}
          currentUserRole={currentUserRole}
          onLogout={handleLogout}
          tasks={tasks}
          onAddTask={handleAddTask}
          onToggleTask={handleToggleTask}
          onSetInProgress={handleSetInProgress}
          onToggleBlock={handleToggleBlock}
          onEditTask={handleEditTask}
          // Pass all other props
          // ...
          parts={parts}
          workplaces={workplaces}
          missingReasons={missingReasons}
          // ...
        />
      ) : (
        <div className="flex items-center justify-center h-full">
            <LoginScreen users={users} onLoginSuccess={handleLogin} />
        </div>
      )}
    </div>
  );
};

export default App;
