```typescript
import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen, { Task, PriorityLevel, InventorySession, Notification } from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons } from './data/mockParts';

// ... (Interfaces remain same as before, REMOVE AD-HOC specific parts if any)

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'SUPERVISOR' | 'LEADER' | 'LOGISTICIAN'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [adhocTasks, setAdhocTasks] = useState<DBItem[]>([]); // Keep state but don't use much logic
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]); // Keep notification logic base

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  const isFirstLoad = useRef(true);

  // ... (useEffect for PWA install prompt) ...

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN') return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  };

  useEffect(() => {
    // ... Users snapshot ...
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase();
        else setUsers(fetchedUsers);
    });
  }, []);

  useEffect(() => {
    // ... Tasks snapshot ...
    const q = query(collection(db, 'tasks')); 
    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      isFirstLoad.current = false;

      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;

        if (a.isDone && b.isDone) {
            const timeA = a.completedAt || 0;
            const timeB = b.completedAt || 0;
            if (timeA !== timeB) return timeB - timeA;
        }

        if (!a.isDone) {
            const pA = priorityOrder[a.priority || 'NORMAL'];
            const pB = priorityOrder[b.priority || 'NORMAL'];
            if (pA !== pB) return pA - pB;
        }

        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []);

  // ... Other snapshots ...
  useEffect(() => { const q = query(collection(db, 'parts'), orderBy('value')); return onSnapshot(q, s => setParts(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem)))); }, []);
  useEffect(() => { const q = query(collection(db, 'workplaces'), orderBy('value')); return onSnapshot(q, s => setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem)))); }, []);
  useEffect(() => { const q = query(collection(db, 'missing_reasons'), orderBy('value')); return onSnapshot(q, s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem)))); }, []);
  // ... BOM, Requests, Roles, Permissions snapshots ...
  useEffect(() => { const q = query(collection(db, 'bom_items')); return onSnapshot(q, s => setBomItems(s.docs.map(d => ({id:d.id, ...d.data()} as BOMItem)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);
  useEffect(() => { const q = query(collection(db, 'roles')); return onSnapshot(q, s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role)))); }, []);
  useEffect(() => { const q = query(collection(db, 'permissions')); return onSnapshot(q, s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission)))); }, []);

  // ... Break Logic ...
  // ... Seed Database ...
  const seedDatabase = async () => {
      const batch = writeBatch(db);
      // Seed users
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      // Seed DB Items
      initialParts.forEach(p => batch.set(doc(collection(db, 'parts')), { value: p }));
      initialWorkplaces.forEach(w => batch.set(doc(collection(db, 'workplaces')), { value: w, standardTime: 0 }));
      initialMissingReasons.forEach(r => batch.set(doc(collection(db, 'missing_reasons')), { value: r }));

      // Roles
      const roleDefs = [
          { name: 'ADMIN', isSystem: true }, { name: 'USER', isSystem: true }, { name: 'SUPERVISOR', isSystem: true }, 
          { name: 'LEADER', isSystem: true }, { name: 'LOGISTICIAN', isSystem: true }
      ];
      roleDefs.forEach(r => batch.set(doc(collection(db, 'roles')), r));

      await batch.commit();
  };

  // ... Handlers ...
  const handleAddTask = async (pn: string | null, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel) => {
    let standardTime = 0;
    const workplaceDef = workplaces.find(w => w.value === wp);
    standardTime = workplaceDef?.standardTime || 0;

    await addDoc(collection(db, 'tasks'), { 
      partNumber: pn, workplace: wp, quantity: qty, quantityUnit: unit, standardTime, 
      isDone:false, priority:prio, createdAt:Date.now(), createdBy:currentUser 
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              isDone: isMissing ? true : t.isDone,
              status: isMissing ? 'completed' : t.status,
              completedAt: isMissing ? Date.now() : t.completedAt,
              completedBy: isMissing ? currentUser : t.completedBy,
              completionTime: isMissing ? new Date().toLocaleTimeString('sk-SK') : t.completionTime
          });
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  // ... Archive logic ...
  const handleArchiveTasks = async () => { /* ... */ return {success:true, count:0}};
  const handleArchiveMissingItems = async () => { /* ... */ return {success:true, count:0}};
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  // ... Other handlers (missing, breaks, etc.) ...

  return (
    <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center">
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout} hasPermission={hasPermission}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} /* ... pass all other handlers */
          parts={parts} workplaces={workplaces} missingReasons={missingReasons}
          // ...
          onArchiveTasks={handleArchiveTasks} onArchiveMissingItems={handleArchiveMissingItems} onFetchArchivedTasks={fetchArchivedTasks}
          // ...
          notifications={notifications}
          // ...
        />
      )}
    </div>
  );
};

export default App;
