import React, { useState, useMemo } from 'react';
import { Task } from './PartSearchScreen';
import { useLanguage } from './LanguageContext';

declare var XLSX: any;

interface MissingItemsTabProps {
    tasks: Task[];
    onDeleteMissingItem: (id: string) => void;
    hasPermission: (perm: string) => boolean;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const MissingItemsTab: React.FC<MissingItemsTabProps> = ({ tasks, onDeleteMissingItem, hasPermission }) => {
    const { t } = useLanguage();
    const [filterPart, setFilterPart] = useState('');
    const [filterWp, setFilterWp] = useState('');

    const missingTasks = useMemo(() => {
        return (tasks || []).filter(t => t.isMissing).sort((a, b) => {
            return (b.completedAt || 0) - (a.completedAt || 0); // Sort by report time desc
        });
    }, [tasks]);

    const filteredTasks = missingTasks.filter(t => {
        const matchPart = (t.partNumber || '').toLowerCase().includes(filterPart.toLowerCase());
        const matchWp = (t.workplace || '').toLowerCase().includes(filterWp.toLowerCase());
        return matchPart && matchWp;
    });

    const formatTime = (ts?: number) => {
        if (!ts) return '-';
        return new Date(ts).toLocaleString('sk-SK');
    };

    const handleExport = () => {
        const data = filteredTasks.map(t => ({
            [t('miss_th_created')]: formatTime(t.createdAt),
            [t('miss_th_part')]: t.partNumber,
            [t('miss_th_wp')]: t.workplace,
            [t('miss_th_reason')]: t.missingReason,
            [t('miss_th_who')]: t.missingReportedBy,
            [t('miss_th_when')]: formatTime(t.completedAt),
            [t('miss_th_creator')]: t.createdBy
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "MissingItems");
        XLSX.writeFile(wb, `Missing_Items_${new Date().toISOString().slice(0,10)}.xlsx`);
    };

    const handleDelete = (id: string) => {
        if(window.confirm(t('miss_delete_confirm'))) {
            onDeleteMissingItem(id);
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4 bg-gray-800 p-4 rounded-xl shadow-lg border border-gray-700">
                <h2 className="text-xl font-bold text-red-400">{t('miss_tab_title')}</h2>
                <button 
                    onClick={handleExport}
                    className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg transition-colors"
                >
                    {t('download_report')}
                </button>
            </div>

            <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                <div className="p-4 grid grid-cols-1 sm:grid-cols-2 gap-4 border-b border-gray-700">
                    <input 
                        type="text" 
                        placeholder="Filter by Part..." 
                        value={filterPart}
                        onChange={e => setFilterPart(e.target.value)}
                        className="bg-gray-700 text-white px-3 py-2 rounded-lg border border-gray-600 focus:outline-none focus:border-teal-500"
                    />
                    <input 
                        type="text" 
                        placeholder="Filter by Workplace..." 
                        value={filterWp}
                        onChange={e => setFilterWp(e.target.value)}
                        className="bg-gray-700 text-white px-3 py-2 rounded-lg border border-gray-600 focus:outline-none focus:border-teal-500"
                    />
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-300">
                        <thead className="bg-gray-700 text-gray-100 uppercase font-medium">
                            <tr>
                                <th className="px-4 py-3">{t('miss_th_created')}</th>
                                <th className="px-4 py-3">{t('miss_th_part')}</th>
                                <th className="px-4 py-3">{t('miss_th_wp')}</th>
                                <th className="px-4 py-3">{t('miss_th_reason')}</th>
                                <th className="px-4 py-3">{t('miss_th_who')}</th>
                                <th className="px-4 py-3">{t('miss_th_when')}</th>
                                <th className="px-4 py-3">{t('miss_th_creator')}</th>
                                {(hasPermission('perm_btn_delete') || hasPermission('perm_manage_db')) && (
                                    <th className="px-4 py-3 text-center">Akcia</th>
                                )}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700">
                            {filteredTasks.length > 0 ? (
                                filteredTasks.map(t => (
                                    <tr key={t.id} className="hover:bg-gray-700/50 transition-colors">
                                        <td className="px-4 py-3">{formatTime(t.createdAt)}</td>
                                        <td className="px-4 py-3 font-bold text-white">{t.partNumber}</td>
                                        <td className="px-4 py-3">{t.workplace}</td>
                                        <td className="px-4 py-3 text-red-300">{t.missingReason}</td>
                                        <td className="px-4 py-3">{t.missingReportedBy}</td>
                                        <td className="px-4 py-3">{formatTime(t.completedAt)}</td>
                                        <td className="px-4 py-3 text-gray-400">{t.createdBy}</td>
                                        {(hasPermission('perm_btn_delete') || hasPermission('perm_manage_db')) && (
                                            <td className="px-4 py-3 text-center">
                                                <button 
                                                    onClick={() => handleDelete(t.id)}
                                                    className="text-red-400 hover:text-red-300 p-2 rounded-full hover:bg-red-900/20 transition-colors"
                                                    title="Vymazať záznam"
                                                >
                                                    <TrashIcon className="w-5 h-5" />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan={8} className="px-4 py-8 text-center text-gray-500 italic">
                                        {t('no_data')}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default MissingItemsTab;
