import React, { useState } from 'react';
import { Role, Permission } from '../App';
import { useLanguage } from './LanguageContext';

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
    </svg>
);

interface PermissionsTabProps {
    roles: Role[];
    permissions: Permission[];
    onAddRole: (name: string) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
}

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, permissions, onAddRole, onDeleteRole, onUpdatePermission }) => {
    const { t } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');

    const sortedRoles = [...(roles || [])].sort((a, b) => {
        if (a.name === 'ADMIN') return -1;
        if (b.name === 'ADMIN') return 1;
        return a.name.localeCompare(b.name);
    });

    const permissionGroups = [
        {
            name: t('perm_group_tabs'),
            items: ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions']
        },
        {
            name: t('perm_group_actions'),
            items: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect']
        },
        {
            name: t('perm_group_mgmt'),
            items: ['perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords', 'perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles']
        }
    ];

    const hasPerm = (roleId: string, permName: string) => {
        return (permissions || []).some(p => p.roleId === roleId && p.permissionName === permName);
    };

    const handleToggle = (role: Role, permName: string, isChecked: boolean) => {
        if (role.name === 'ADMIN' && !isChecked) return; // Admin always has all
        onUpdatePermission(permName, role.name, isChecked);
    };

    const handleAdd = () => {
        if (newRoleName.trim()) {
            onAddRole(newRoleName.trim());
            setNewRoleName('');
        }
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-fade-in">
            <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700">
                <h2 className="text-xl font-bold text-teal-400 mb-6 flex items-center gap-2">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
                    {t('sect_roles')}
                </h2>

                <div className="flex gap-4 mb-8 bg-gray-900 p-4 rounded-lg border border-gray-700">
                    <input 
                        type="text" 
                        value={newRoleName}
                        onChange={e => setNewRoleName(e.target.value)}
                        placeholder={t('role_name_place')}
                        className="flex-1 bg-gray-800 border border-gray-600 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                    <button 
                        onClick={handleAdd}
                        className="bg-teal-600 hover:bg-teal-700 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2 transition-colors"
                    >
                        <PlusIcon className="w-5 h-5" />
                        {t('role_add_btn')}
                    </button>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm border-collapse">
                        <thead>
                            <tr>
                                <th className="p-4 bg-gray-900 text-gray-400 border border-gray-700 font-bold sticky left-0 z-10 w-64">Oprávnenie</th>
                                {sortedRoles.map(role => (
                                    <th key={role.id} className="p-4 bg-gray-900 text-teal-400 border border-gray-700 font-bold text-center min-w-[100px]">
                                        <div className="flex flex-col items-center gap-2">
                                            <span>{role.name}</span>
                                            {!role.isSystem && (
                                                <button 
                                                    onClick={() => { if(window.confirm('Delete role?')) onDeleteRole(role.id); }}
                                                    className="text-red-500 hover:text-red-400 p-1 hover:bg-red-900/30 rounded"
                                                >
                                                    <TrashIcon className="w-4 h-4" />
                                                </button>
                                            )}
                                        </div>
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {permissionGroups.map((group, groupIdx) => (
                                <React.Fragment key={groupIdx}>
                                    <tr className="bg-gray-700/50">
                                        <td colSpan={sortedRoles.length + 1} className="p-3 font-bold text-gray-200 border border-gray-700 uppercase tracking-wider text-xs">
                                            {group.name}
                                        </td>
                                    </tr>
                                    {group.items.map((perm) => (
                                        <tr key={perm} className="hover:bg-gray-700/30 transition-colors">
                                            <td className="p-3 border border-gray-700 text-gray-300 font-medium sticky left-0 bg-gray-800 z-10">
                                                {t(perm as any)}
                                            </td>
                                            {sortedRoles.map(role => {
                                                const checked = role.name === 'ADMIN' ? true : hasPerm(role.id, perm);
                                                return (
                                                    <td key={role.id} className="p-3 border border-gray-700 text-center">
                                                        <input 
                                                            type="checkbox" 
                                                            checked={checked}
                                                            onChange={e => handleToggle(role, perm, e.target.checked)}
                                                            disabled={role.name === 'ADMIN'}
                                                            className="w-5 h-5 rounded border-gray-600 text-teal-600 focus:ring-teal-500 bg-gray-700 cursor-pointer"
                                                        />
                                                    </td>
                                                );
                                            })}
                                        </tr>
                                    ))}
                                </React.Fragment>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default PermissionsTab;
